import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Store, Plus, Loader2, Package, ImageIcon } from 'lucide-react';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const CLOUD_NAME = "dwpgncjgn"; 

const PanelCliente = () => {
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const [loading, setLoading] = useState(true);
    const [userCoords, setUserCoords] = useState(null);
    const { addToCart, count, total } = useCart();

    // 1. Obtener ubicación del usuario
    useEffect(() => {
        navigator.geolocation.getCurrentPosition(
            (pos) => setUserCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
            (err) => console.warn("Ubicación denegada o no disponible"),
            { enableHighAccuracy: true }
        );
    }, []);

    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                
                const agrupado = data.reduce((acc, oferta) => {
                    const localData = oferta.local || {};
                    const nombreLocal = localData.nombre || 'Sucursal';
                    if (!acc[nombreLocal]) acc[nombreLocal] = { info: localData, productos: [] };
                    acc[nombreLocal].productos.push(oferta);
                    return acc;
                }, {});

                setOfertasPorLocal(agrupado);
            } catch (err) {
                console.error("Error al cargar:", err);
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    // 2. Cálculo de distancia Real
    const getDistancia = (localLocation) => {
        if (!userCoords || !localLocation || !localLocation.lat) return "Distancia desconocida";
        
        const R = 6371; // Radio de la Tierra en km
        const dLat = (localLocation.lat - userCoords.lat) * Math.PI / 180;
        const dLon = (localLocation.lng - userCoords.lng) * Math.PI / 180;
        const a = 
            Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(userCoords.lat * Math.PI / 180) * Math.cos(localLocation.lat * Math.PI / 180) * Math.sin(dLon/2) * Math.sin(dLon/2);
        const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
        const d = R * c;
        return d < 1 ? `${(d * 1000).toFixed(0)} mts` : `${d.toFixed(1)} km`;
    };

    const construirUrlImagen = (publicId) => {
        if (!publicId || publicId === 'placeholder_id') return null;
        return `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_400,h_300,c_fill,f_auto,q_auto/${publicId}`;
    };

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p>Sincronizando con la nube...</p>
        </div>
    );

    return (
        <div style={container}>
            <header style={headerStyle}>
                <div>
                    <h1 style={titleStyle}>Ofertas del Día</h1>
                    {userCoords && (
                        <div style={{display:'flex', alignItems:'center', gap:5, color:'#22c55e', fontSize:'0.8rem'}}>
                            <MapPin size={12}/> Ubicación activa
                        </div>
                    )}
                </div>
                <div style={cartFloatingCard}>
                    <ShoppingCart color="#e67e22" size={20} />
                    <span style={{fontWeight: 'bold'}}>${total.toLocaleString()}</span>
                    <div style={badgeCount}>{count}</div>
                </div>
            </header>

            {Object.keys(ofertasPorLocal).map(nombre => (
                <div key={nombre} style={localSection}>
                    <div style={localHeader}>
                        <div style={localIconCircle}>
                            <Store size={20} color="white" />
                        </div>
                        <div style={{flex: 1}}>
                            <div style={{display:'flex', justifyContent:'space-between', alignItems:'flex-start'}}>
                                <h2 style={localTitle}>{nombre}</h2>
                                <span style={distanciaBadge}>
                                    <MapPin size={12} /> {getDistancia(ofertasPorLocal[nombre].info?.location)}
                                </span>
                            </div>
                            <p style={localSub}>{ofertasPorLocal[nombre].info?.direccion || 'Dirección no disponible'}</p>
                        </div>
                    </div>

                    <div style={scrollContainer}>
                        {ofertasPorLocal[nombre].productos.map(prod => {
                            const urlImagen = construirUrlImagen(prod.publicId);
                            
                            return (
                                <div key={prod._id} style={productCard}>
                                    <div style={imageBox}>
                                        {urlImagen ? (
                                            <img 
                                                src={urlImagen} 
                                                alt={prod.producto} 
                                                style={imgStyle}
                                                onError={(e) => { e.target.style.display = 'none'; e.target.parentNode.style.background = '#f1f5f9'; }}
                                            />
                                        ) : (
                                            <div style={placeholderIcon}>
                                                <ImageIcon size={30} color="#cbd5e1" />
                                                <span style={{fontSize:'0.7rem', color:'#cbd5e1'}}>Sin foto</span>
                                            </div>
                                        )}
                                        
                                        <div style={stockBadge(prod.stock)}>
                                            {prod.stock > 0 ? `${prod.stock} disp.` : 'Agotado'}
                                        </div>
                                    </div>

                                    <div style={infoBox}>
                                        <div style={categoryTag}>{prod.categoria}</div>
                                        <h4 style={prodTitle}>{prod.producto}</h4>
                                        <div style={priceContainer}>
                                            <span style={newPrice}>${prod.precioNuevo}</span>
                                            <span style={oldPrice}>${prod.precioViejo}</span>
                                        </div>
                                        <button 
                                            style={prod.stock > 0 ? btnAdd : btnDisabled}
                                            onClick={() => addToCart(prod)}
                                            disabled={prod.stock <= 0}
                                        >
                                            <Plus size={16} /> Agregar
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            ))}
        </div>
    );
};

// --- ESTILOS ---
const container = { padding: '20px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'system-ui' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const titleStyle = { fontSize: '2rem', fontWeight: '900', color: '#1e293b', margin: 0 };
const cartFloatingCard = { background: '#1e293b', color: 'white', padding: '12px 24px', borderRadius: '50px', display: 'flex', alignItems: 'center', gap: '15px', boxShadow: '0 10px 20px rgba(0,0,0,0.1)' };
